parameters.inputSchema:
{
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "id": {
        "type": "string",
        "description": "The 43-character componentkey post identifier, passed through from the input"
      },
      "status": {
        "type": "string",
        "enum": ["pass", "fail"],
        "description": "pass = quality content, fail = slop to be hidden"
      }
    },
    "required": ["id", "status"],
    "additionalProperties": false
  }
}
